export async function seedRNQuestions(): Promise<{
  total: number;
  inserted: number;
  skipped: number;
  errors: number;
  details: string[];
}> {
  const canQuestions = canadianRNQuestions();
  const usQuestions = americanRNQuestions();
  const details: string[] = [];
  let inserted = 0;
  let skipped = 0;
  let errors = 0;

  details.push(`Canadian RN questions generated: ${canQuestions.length}`);
  details.push(`American RN questions generated: ${usQuestions.length}`);

  const allQuestions: Array<{ q: RNQuestion; regionScope: string; exam: string }> = [
    ...canQuestions.map(q => ({ q, regionScope: "CAN", exam: "NCLEX-RN" })),
    ...usQuestions.map(q => ({ q, regionScope: "US", exam: "NCLEX-RN" })),
  ];

  for (const { q, regionScope, exam } of allQuestions) {
    const hash = stemHash(q.stem);

    try {
      const existing = await pool.query(
        `SELECT id FROM exam_questions WHERE stem_hash = $1 AND exam = $2`,
        [hash, exam]
      );

      if (existing.rows.length > 0) {
        skipped++;
        continue;
      }

      await pool.query(
        `INSERT INTO exam_questions (
          tier, exam, question_type, status, published_at, stem, options, correct_answer,
          rationale, difficulty, body_system, topic, subtopic, region_scope, career_type,
          stem_hash, scenario, exhibit_data, clinical_pearl, tags
        ) VALUES ($1, $2, $3, $4, NOW(), $5, $6, $7, $8, $9, $10, $11, $12, $13, 'nursing', $14, $15, $16, $17, $18)`,
        [
          "rn",
          exam,
          "multiple_choice",
          "published",
          q.stem,
          JSON.stringify(q.options),
          JSON.stringify(q.correctAnswer),
          q.rationale,
          q.difficulty,
          q.bodySystem,
          q.topic,
          q.subtopic,
          regionScope,
          hash,
          q.scenario || null,
          null,
          q.clinicalPearl,
          q.tags,
        ]
      );
      inserted++;
    } catch (dbErr: any) {
      errors++;
      details.push(`DB error: ${dbErr.message.substring(0, 150)}`);
    }
  }

  details.push(`Inserted: ${inserted}`);
  details.push(`Skipped (duplicates): ${skipped}`);
  details.push(`Errors: ${errors}`);

  return {
    total: canQuestions.length + usQuestions.length,
    inserted,
    skipped,
    errors,
    details,
  };
}
